const patch = "*** Begin Patch
*** Update File: /app/launch_qwen3.5_27b_sglang.sh
@@
 export SGLANG_USE_AITER=1
 export SGLANG_USE_CUDA_IPC_TRANSPORT=1
+# Keep opened multimodal pool IPC handles alive across concurrent reuse.
+export SGLANG_USE_IPC_POOL_HANDLE_CACHE=1
*** Add File: /app/analysis.json
+{
+  "root_cause": "With concurrent multimodal requests, the sender's pooled device buffer is recycled while the receiver still has an IPC descriptor to reconstruct. Because opened pool-level IPC handles were not cached, the receiver could reopen a handle after the backing allocation had been freed or reused, producing a stale device pointer and HIP invalid-device-pointer failure.",
+  "fix": "Set SGLANG_USE_IPC_POOL_HANDLE_CACHE=1 in launch_qwen3.5_27b_sglang.sh. This keeps the opened multimodal CUDA/HIP IPC pool handle storage cached across reuse while leaving SGLANG_USE_CUDA_IPC_TRANSPORT=1 enabled.",
+  "evidence": "The crash log reports '[2026-07-16 12:50:59 TP1] Failed to deserialize from CUDA IPC handle (HIP error: invalid device pointer', then shows reconstruct_on_target_device in cuda_ipc_transport_utils.py calling torch.UntypedStorage._new_shared_cuda and raises 'torch.AcceleratorError: HIP error: invalid device pointer'. The same log also reports 'MmItemMemoryPool has no free chunk large enough ... falling back to non-IPC transport' under the concurrent workload."
+}
*** End Patch";
text(await tools.apply_patch(patch));
const r = await tools.update_plan({explanation:"Located the disabled pool-handle cache and applied the configuration fix while preserving CUDA IPC transport.",plan:[
